"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[24116],{46314:e=>{e.exports=JSON.parse('{"functions":[{"name":"RegisterTeleportDataProvider","desc":"Registers a shared provider (contributes to every player\'s teleport data). See\\n[TeleportDataBuilder.RegisterTeleportDataProvider]. Returns an unregister function.","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"provider","desc":"","lua_type":"TeleportDataProvider"}],"returns":[{"desc":"","lua_type":"() -> ()"}],"function_type":"static","source":{"line":121,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"RegisterPerPlayerTeleportDataProvider","desc":"Registers a per-player provider. See [TeleportDataBuilder.RegisterPerPlayerTeleportDataProvider].\\nReturns an unregister function.","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"provider","desc":"","lua_type":"PerPlayerTeleportDataProvider"}],"returns":[{"desc":"","lua_type":"() -> ()"}],"function_type":"static","source":{"line":135,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"BuildTeleportData","desc":"Builds the teleport data envelope for a teleport of the given players. See\\n[TeleportDataBuilder.BuildTeleportData].","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"players","desc":"","lua_type":"{ Player }"},{"name":"baseData","desc":"","lua_type":"{ [string]: any }?"}],"returns":[{"desc":"","lua_type":"{ [string]: any }"}],"function_type":"static","source":{"line":150,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"_getUserId","desc":"Resolves the UserId used to key a player\'s envelope slice. A method so tests can stand in a fake\\nplayer (which has no UserId) by overriding it.","params":[{"name":"_self","desc":"","lua_type":"TeleportDataService"},{"name":"player","desc":"","lua_type":"Player"}],"returns":[{"desc":"","lua_type":"number"}],"function_type":"static","source":{"line":165,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"PromiseArrivedData","desc":"Returns the *unified* teleport data the player arrived with -- the trusted band (server join data)\\nmerged over the non-trusted band (client-replicated), trusted winning -- or nil. Resolves once the\\nclient has replicated its band, or when the bounded timeout falls back to the trusted band alone.\\n\\nThis is the everyday accessor. It may contain client-authored keys, so treat it as a *request*, not\\nan authority; for authoritative reads use [TeleportDataService.PromiseTrustedArrivedData].","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"player","desc":"","lua_type":"Player"}],"returns":[{"desc":"","lua_type":"Promise<{ [string]: any }?>"}],"function_type":"static","source":{"line":180,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"PromiseTrustedArrivedData","desc":"Returns the trusted-band teleport data the player arrived with (server-authored, from join data), or\\nnil. Safe to authorize on -- a client can never place data here. Resolves once the arrival is sealed.","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"player","desc":"","lua_type":"Player"}],"returns":[{"desc":"","lua_type":"Promise<{ [string]: any }?>"}],"function_type":"static","source":{"line":197,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"PromiseNonTrustedArrivedData","desc":"Returns the non-trusted-band teleport data the player arrived with (client-replicated), or nil.\\nRarely needed directly; prefer the unified [TeleportDataService.PromiseArrivedData].","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"player","desc":"","lua_type":"Player"}],"returns":[{"desc":"","lua_type":"Promise<{ [string]: any }?>"}],"function_type":"static","source":{"line":214,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"PromiseArrivedValue","desc":"Returns the unified value the player arrived with under `key`, or nil.","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"player","desc":"","lua_type":"Player"},{"name":"key","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"Promise<any>"}],"function_type":"static","source":{"line":231,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"PromiseHasArrivedValue","desc":"Returns whether the player arrived with a unified value under `key`.","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"player","desc":"","lua_type":"Player"},{"name":"key","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"Promise<boolean>"}],"function_type":"static","source":{"line":249,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"PromiseTrustedArrivedValue","desc":"Returns the trusted-band value the player arrived with under `key`, or nil. Safe to authorize on.","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"player","desc":"","lua_type":"Player"},{"name":"key","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"Promise<any>"}],"function_type":"static","source":{"line":262,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"PromiseHasTrustedArrivedValue","desc":"Returns whether the player arrived with a trusted-band value under `key`.","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"player","desc":"","lua_type":"Player"},{"name":"key","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"Promise<boolean>"}],"function_type":"static","source":{"line":280,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"PromiseArrivedValueIsTrusted","desc":"Returns whether the unified value for `key` came from the trusted band -- i.e. whether it is safe to\\nauthorize on. Defense-in-depth for code that reads the unified view but must occasionally assert\\nprovenance without a second read.","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"player","desc":"","lua_type":"Player"},{"name":"key","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"Promise<boolean>"}],"function_type":"static","source":{"line":295,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"SetTrustedArrivedTeleportDataForTesting","desc":"Overrides the *trusted* arrived band for a player. Test seam -- headless servers have no join data, so\\nspecs inject what a player would have arrived with from a server teleport. Must be set before any read\\nseals the arrival.","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"player","desc":"","lua_type":"Player"},{"name":"data","desc":"","lua_type":"{ [string]: any }?"}],"returns":[],"function_type":"static","source":{"line":314,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"SetNonTrustedArrivedTeleportDataForTesting","desc":"Simulates the client\'s non-trusted band arriving (the replication the real client pushes). Test seam.\\nFirst arrival wins and seals; later calls are ignored, mirroring production first-wins semantics.","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"player","desc":"","lua_type":"Player"},{"name":"data","desc":"","lua_type":"{ [string]: any }?"}],"returns":[],"function_type":"static","source":{"line":334,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}},{"name":"SetReplicationTimeoutForTesting","desc":"Sets the bounded wait before a read falls back to the trusted band alone. Test seam, so a spec can\\ndrive the timeout path deterministically without waiting the production window.","params":[{"name":"self","desc":"","lua_type":"TeleportDataService"},{"name":"seconds","desc":"","lua_type":"number"}],"returns":[],"function_type":"static","source":{"line":350,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}}],"properties":[],"types":[],"name":"TeleportDataService","desc":"Server half of the symmetric teleport-data surface. Two responsibilities:\\n\\n* **Building** teleport data through a shared [TeleportDataBuilder], so every teleport site assembles\\n  the same envelope from the same providers (see [TeleportDataService.BuildTeleportData]).\\n* **Reading** the data a player arrived with, as a *unified* view across two trust bands.\\n\\nThe trust split is the load-bearing idea. A player\'s arrived data reaches the server two ways:\\n\\n* the **trusted** band -- `player:GetJoinData().TeleportData` -- which Roblox only populates for a\\n  *server*-initiated teleport, so it is genuinely server-authored and safe to authorize on; and\\n* the **non-trusted** band -- what the *client* read from its own local teleport data\\n  (`GetLocalPlayerTeleportData`) and replicated back to us. A client-initiated teleport (e.g. a menu\\n  teleporting the local player) only ever reaches the server this way, so without it the server is\\n  blind to data the client can see.\\n\\nThe unified read ([TeleportDataService.PromiseArrivedData]) merges both with the **trusted band\\nwinning**, so a client can never override a key the server set. Because the non-trusted band arrives\\nover the network, every read is a [Promise]: it resolves once the client has replicated (or a bounded\\ntimeout falls back to the trusted band alone, so a stale client can never hang a read forever). Code\\nthat must *not* trust the client reads the trusted band explicitly via\\n[TeleportDataService.PromiseTrustedArrivedData]; the unified accessor is deliberately un-named for\\ntrust so trusting client data is always a visible choice.","realm":["Server"],"source":{"line":29,"path":"src/teleportserviceutils/src/Server/TeleportDataService.lua"}}')}}]);